def test_open_checking_deposit_below_minimum_rejected(verified_customer_token, api_client):
    payload = {"initial_deposit": 10}
    resp = api_client.post(
        "/accounts/checking",
        json=payload,
        headers=<auth_header>(verified_customer_token),
    )
    assert resp.status_code == 422, f"Expected 422, got {resp.status_code}"
    body = resp.json()
    assert <error_code_present>(body, "DEPOSIT_OUT_OF_RANGE")

