def test_open_checking_unverified_customer_forbidden(unverified_customer_token, api_client):
    payload = {"initial_deposit": 5000}
    resp = api_client.post(
        "/accounts/checking",
        json=payload,
        headers=<auth_header>(unverified_customer_token),
    )
    assert resp.status_code == 403, f"Expected 403 for unverified customer, got {resp.status_code}"
    body = resp.json()
    assert "account_id" not in body, "account_id must not be present in 403 response"

def test_open_checking_unverified_customer_deposit_below_min_returns_403_not_422(unverified_customer_token, api_client):
    payload = {"initial_deposit": 10}
    resp = api_client.post(
        "/accounts/checking",
        json=payload,
        headers=<auth_header>(unverified_customer_token),
    )
    assert resp.status_code == 403, (
        f"Auth guard must take precedence: expected 403, got {resp.status_code}"
    )
    body = resp.json()
    assert "account_id" not in body
